  // ==========================================
  // NOTIFICATION PREFERENCES TESTS
  // ==========================================

  describe('GET /api/communication/preferences', () => {
    it('should get user notification preferences', async () => {
      // Set up test user
      app.use((req: any, res, next) => {
        req.user = testUsers[1]; // Manager user
        next();
      });

      // Mock existing preferences response
      const mockPreferences = allNotificationTypes.map((type, index) => ({
        id: uuidv4(),
        userId: testUsers[1].id,
        notificationType: type,
        frequency: index % 2 === 0 ? 'monthly' : 'weekly',
        isEnabled: true,
        createdAt: new Date(),
        updatedAt: new Date(),
      }));

      const { db } = await import('../../server/db');
      const mockSelect = db.select as jest.MockedFunction<any>;
      mockSelect.mockReturnValueOnce({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue(mockPreferences),
        }),
      });

      const response = await request(app)
        .get('/api/communication/preferences')
        .expect(200);

      expect(Array.isArray(response.body)).toBe(true);
      expect(response.body).toHaveLength(17); // Should return all 17 notification types
      if (response.body.length > 0) {
        expect(response.body[0]).toHaveProperty('notificationType');
        expect(response.body[0]).toHaveProperty('frequency');
        expect(response.body[0]).toHaveProperty('isEnabled');
      }
    });

    it('should require authentication', async () => {
      // Override authentication to return no user
      app.use((req: any, res, next) => {
        req.user = undefined;
        next();
      });

      const response = await request(app)
        .get('/api/communication/preferences')
        .expect(401);

      expect(response.body).toHaveProperty('message', 'Authentication required');
      expect(response.body).toHaveProperty('code', 'AUTH_REQUIRED');
    });
  });

  describe('PUT /api/communication/preferences', () => {
    it('should update user notification preferences', async () => {
      app.use((req: any, res, next) => {
        req.user = testUsers[1]; // Manager user
        next();
      });

      const updateData = [
        {
          notificationType: 'bill_reminder',
          frequency: 'weekly',
          isEnabled: true,
        },
        {
          notificationType: 'maintenance_update',
          frequency: 'immediate',
          isEnabled: false,
        },
      ];

      const { db } = await import('../../server/db');
      const mockInsert = db.insert as jest.MockedFunction<any>;
      const mockSelect = db.select as jest.MockedFunction<any>;

      // Mock the insert operations
      mockInsert.mockReturnValue({
        values: jest.fn().mockReturnValue({
          onConflictDoUpdate: jest.fn().mockResolvedValue([]),
        }),
      });

      // Mock the final select operation
      mockSelect.mockReturnValue({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue(updateData.map(item => ({
            id: uuidv4(),
            userId: testUsers[1].id,
            ...item,
            createdAt: new Date(),
            updatedAt: new Date(),
          }))),
        }),
      });

      const response = await request(app)
        .put('/api/communication/preferences')
        .send(updateData)
        .expect(200);

      expect(Array.isArray(response.body)).toBe(true);
    });

    it('should validate request data', async () => {
      app.use((req: any, res, next) => {
        req.user = testUsers[1]; // Manager user
        next();
      });

      const invalidData = [
        {
          notificationType: 'invalid_type',
          frequency: 'invalid_frequency',
          isEnabled: 'not_boolean',
        },
      ];

      const response = await request(app)
        .put('/api/communication/preferences')
        .send(invalidData)
        .expect(400);

      expect(response.body).toHaveProperty('_error', 'Validation error');
      expect(response.body).toHaveProperty('message', 'Invalid preference data provided');
    });

    it('should require authentication', async () => {
      app.use((req: any, res, next) => {
        req.user = undefined;
        next();
      });

      const response = await request(app)
        .put('/api/communication/preferences')
        .send([])
        .expect(401);

      expect(response.body).toHaveProperty('code', 'AUTH_REQUIRED');
    });
  });

