  // ==========================================
  // ERROR HANDLING AND EDGE CASES
  // ==========================================

  describe('Error Handling', () => {
    it('should handle database errors gracefully', async () => {
      app.use((req: any, res, next) => {
        req.user = testUsers[1]; // Manager user
        next();
      });

      const { db } = await import('../../server/db');
      const mockSelect = db.select as jest.MockedFunction<any>;
      mockSelect.mockImplementation(() => {
        throw new Error('Database connection failed');
      });

      const response = await request(app)
        .get('/api/communication/preferences')
        .expect(500);

      expect(response.body).toHaveProperty('_error', 'Internal server error');
    });

    it('should handle email service failures gracefully', async () => {
      app.use((req: any, res, next) => {
        req.user = testUsers[1]; // Manager user
        next();
      });

      const { emailService } = await import('../../server/services/email-service');
      const mockSendEmail = emailService.sendGeneralCommunication as jest.MockedFunction<any>;
      mockSendEmail.mockRejectedValue(new Error('Email service unavailable'));

      const { db } = await import('../../server/db');
      const mockSelect = db.select as jest.MockedFunction<any>;
      mockSelect.mockReturnValue({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([
            { organizationId: testOrgs[0].id },
          ]),
        }),
      });

      const mockInsert = db.insert as jest.MockedFunction<any>;
      mockInsert.mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([{
            id: uuidv4(),
            organizationId: testOrgs[0].id,
            createdBy: testUsers[1].id,
            title: 'Test Communication',
            content: 'Test content',
            isUrgent: false,
            recipientRoles: ['resident'],
            createdAt: new Date(),
          }]),
        }),
      });

      const newCommunication = {
        organizationId: testOrgs[0].id,
        title: 'Test Communication',
        content: 'Test content',
        isUrgent: false,
        recipientRoles: ['resident'],
      };

      // Should still create communication even if email fails
      const response = await request(app)
        .post('/api/communication/general')
        .send(newCommunication)
        .expect(201);

      expect(response.body).toHaveProperty('id');
    });
  });
